	assert.Equal(t, []Ansi{"38;2;52;101;164"}, result)
}

// TestGradientLastSingleStopAutoShade verifies GradientLast mirrors GradientCells' shading
// for a hex single stop, and falls back to the raw stop for one it can't shade without a
// resolver (keyword, palette reference).
func TestGradientLastSingleStopAutoShade(t *testing.T) {
	assert.Equal(t, Ansi("#28568c"), Ansi("linear-gradient(#3465A4)").GradientLast(), "hex stop shades to the same color GradientCells renders the last cell as")
	assert.Equal(t, Ansi("parentBackground"), Ansi("linear-gradient(parentBackground)").GradientLast(), "a keyword stop can't be shaded without a resolver, so it passes through unchanged")
	assert.Equal(t, Ansi("p:red"), Ansi("linear-gradient(p:red)").GradientLast(), "a palette reference can't be shaded without a resolver, so it passes through unchanged")
}

