// TestGradientCellsSingleStopAutoShade verifies linear-gradient(#color) — a single
// explicit stop — spreads into a two-stop gradient running from the exact configured
// color to a fixed darker shade of it, instead of collapsing like an ordinary invalid
// (< 2 stop) gradient. The first cell must be the unmodified configured color (matching
// GradientFirst) and the last must match GradientLast, so separators/caps line up.
func TestGradientCellsSingleStopAutoShade(t *testing.T) {
	gradient := Ansi("linear-gradient(#3465A4)")
	result := GradientCells(gradient, 5, &Defaults{}, false, nil, nil)
	assert.Len(t, result, 5)

	assert.Equal(t, Ansi("38;2;52;101;164"), result[0], "the first cell must be the unmodified configured color")

	expectedLast := GradientCells(Ansi("linear-gradient(#3465A4, "+gradient.GradientLast().String()+")"), 5, &Defaults{}, false, nil, nil)
	assert.Equal(t, expectedLast[len(expectedLast)-1], result[len(result)-1], "the last cell must match GradientLast, the color separators/caps use")

	assert.NotEqual(t, result[0], result[len(result)-1], "the segment must actually shade, not render solid")
}

// TestGradientCellsSingleStopAutoShadeSingleCell verifies a single-cell segment (too
// narrow to show any blend) renders the configured color unmodified, not a shaded
// endpoint.
func TestGradientCellsSingleStopAutoShadeSingleCell(t *testing.T) {
	result := GradientCells("linear-gradient(#3465A4)", 1, &Defaults{}, false, nil, nil)
	assert.Equal(t, []Ansi{"38;2;52;101;164"}, result)
}

// TestGradientLastSingleStopAutoShade verifies GradientLast mirrors GradientCells' shading
// for a hex single stop, and falls back to the raw stop for one it can't shade without a
// resolver (keyword, palette reference).
func TestGradientLastSingleStopAutoShade(t *testing.T) {
	assert.Equal(t, Ansi("#28568c"), Ansi("linear-gradient(#3465A4)").GradientLast(), "hex stop shades to the same color GradientCells renders the last cell as")
	assert.Equal(t, Ansi("parentBackground"), Ansi("linear-gradient(parentBackground)").GradientLast(), "a keyword stop can't be shaded without a resolver, so it passes through unchanged")
	assert.Equal(t, Ansi("p:red"), Ansi("linear-gradient(p:red)").GradientLast(), "a palette reference can't be shaded without a resolver, so it passes through unchanged")
}

