package color

import (
	"fmt"
	"math"
	"testing"

	"github.com/lucasb-eyer/go-colorful"
)

func candidateShade(base colorful.Color, slope, floor, ceil float64) colorful.Color {
	h, c, l := base.Hcl()
	delta := math.Max(floor, math.Min(ceil, slope*l))
	l = math.Max(0.02, l-delta)
	shade := colorful.Hcl(h, c, l)
	for !shade.IsValid() && c > 0 {
		c -= 0.005
		shade = colorful.Hcl(h, c, l)
	}
	return shade.Clamped()
}

func TestProbeCandidates(t *testing.T) {
	bases := map[string]colorful.Color{}
	for _, hex := range []string{"#179299", "#e64553", "#3465A4", "#202030", "#FFD700"} {
		c, _ := colorful.Hex(hex)
		bases[hex] = c
	}

	for _, cand := range []struct{ slope, floor, ceil float64 }{
		{0.18, 0.06, 0.12}, // current
		{0.09, 0.03, 0.06},
		{0.07, 0.025, 0.05},
		{0.06, 0.02, 0.04},
	} {
		fmt.Printf("--- slope=%.3f floor=%.3f ceil=%.3f ---\n", cand.slope, cand.floor, cand.ceil)
		for hex, base := range bases {
			shade := candidateShade(base, cand.slope, cand.floor, cand.ceil)
			de := base.DistanceLab(shade)
			fmt.Printf("  %s -> %s  total ΔE=%.2f  per-step(2 steps)=%.2f  per-step(1 step)=%.2f\n", hex, shade.Hex(), de, de/2, de)
		}
	}
}
EOF
