package color

import (
	"math"
	"strconv"
	"strings"

	"github.com/gookit/color"
	"github.com/jandedobbeleer/oh-my-posh/src/log"
	"github.com/lucasb-eyer/go-colorful"
)

const (
	gradientPrefix = "linear-gradient("
	gradientSuffix = ")"
)

// IsGradient reports whether c is a gradient definition, e.g. `linear-gradient(#FF0000, #0000FF)`.
func (c Ansi) IsGradient() bool {
	return strings.HasPrefix(c.String(), gradientPrefix)
}

// GradientStops performs syntax parsing only: it splits the comma-separated stop list inside
// `linear-gradient(...)` and trims whitespace around each stop. It does not resolve palette
// references or validate that a stop is a color. Returns nil when c is not a gradient, the
// closing paren is missing, the body contains a nested paren (angle/direction syntax is
// reserved but not implemented), or any stop is empty.
func (c Ansi) GradientStops() []Ansi {
	if !c.IsGradient() {
		return nil
	}

	value := c.String()
	if !strings.HasSuffix(value, gradientSuffix) {
		return nil
	}

	body := value[len(gradientPrefix) : len(value)-len(gradientSuffix)]
	if strings.ContainsAny(body, "()") {
		return nil
	}

	parts := strings.Split(body, ",")
	stops := make([]Ansi, 0, len(parts))

	for _, part := range parts {
		stop := strings.TrimSpace(part)
		if stop == "" {
			return nil
		}

		stops = append(stops, Ansi(stop))
	}

	return stops
}

// GradientFirst returns the first stop of the gradient. It returns c unchanged when c is not
// a gradient, or when the gradient syntax is invalid.
func (c Ansi) GradientFirst() Ansi {
	stops := c.GradientStops()
	if len(stops) == 0 {
		return c
	}

	return stops[0]
}

// GradientLast returns the last stop of the gradient. It returns c unchanged when c is not
// a gradient, or when the gradient syntax is invalid. A single-stop (auto-shade) gradient's
// last stop is the same darkened shade GradientCells renders the segment's last cell as,
// so separators, diamond caps, and parentBackground/parentForeground line up with the body
// instead of jumping back to the unshaded configured color.
func (c Ansi) GradientLast() Ansi {
	stops := c.GradientStops()
	if len(stops) == 0 {
		return c
	}

	last := stops[len(stops)-1]

	if len(stops) == 1 {
		if clr, err := colorful.Hex(last.String()); err == nil {
			return Ansi(autoShade(clr).Hex())
		}
	}

	return last
}

// GradientCells resolves each stop of the gradient c — keywords like parentBackground against
// current/parents, palette references through resolver — parses the result as a hex color, and
// interpolates across cells steps in HCL space. It returns one ready-to-print ANSI color code
// per cell, honoring the package-level TrueColor flag: a truecolor escape when true, a gookit
// C256 downgrade when false. cells == 1 returns only the first stop. Returns nil when fewer
// than two stops resolve to a valid color; the caller falls back to a single collapsed color
// per the gradient-invalid rule.
func GradientCells(c Ansi, cells int, resolver String, isBackground bool, current *Set, parents []*Set) []Ansi {
	if cells <= 0 {
		return nil
	}

	stops := c.GradientStops()
	if len(stops) == 0 {
		log.Errorf("gradient %s: invalid syntax, expected linear-gradient(stop, stop, ...)", c)
		return nil
	}

	colors := make([]colorful.Color, 0, len(stops))

	for _, stop := range stops {
		// a keyword stop (parentBackground, foreground, ...) resolves against the
		// segment context first; a parent gradient collapses to its last stop there.
		resolved := stop.Resolve(current, parents)

		resolved, err := resolver.Resolve(resolved)
		if err != nil {
			log.Errorf("gradient %s: unable to resolve stop %s: %s", c, stop, err)
			continue
		}

		// the OS accent color only resolves in ToAnsi, to a truecolor payload
		// rather than hex; parseTrueColor recovers the RGB triplet from it.
		if resolved == Accent {
			resolved = resolver.ToAnsi(Accent, false)
		}

		clr, err := colorful.Hex(resolved.String())
		if err != nil {
			var ok bool
			if clr, ok = parseTrueColor(resolved); !ok {
				log.Errorf("gradient %s: stop %s does not resolve to a color, only hex colors, palette references, and keywords resolving to a color can be interpolated", c, stop)
				continue
			}
		}

		colors = append(colors, clr)
	}

	// a single explicit stop, e.g. linear-gradient(#3465a4), is an auto-shade request:
	// turn the one resolved color into a real two-stop gradient running from that exact
	// color to a fixed darker shade of it, reusing the interpolation below unchanged. The
	// segment's own cell count (fewer cells = coarser steps) already gives narrow segments
	// a gentler ramp, same as any other gradient; see GradientLast for the matching edge.
	if len(stops) == 1 {
		if len(colors) == 0 {
			log.Errorf("gradient %s: stop does not resolve to a color", c)
			return nil
		}

		colors = []colorful.Color{colors[0], autoShade(colors[0])}
	}

	if len(colors) < 2 {
		log.Errorf("gradient %s: needs at least two valid stops, rendering the last stop as a solid color", c)
		return nil
	}

	if cached, ok := gradientCellCache[gradientKey(colors, cells, isBackground)]; ok {
		return cached
	}

	if cells == 1 {
		return cacheGradientCells(colors, cells, isBackground, []Ansi{ansiFromColorful(colors[0], isBackground)})
	}

	segments := len(colors) - 1
	result := make([]Ansi, cells)

	for i := range cells {
		position := float64(i) / float64(cells-1) * float64(segments)

		segment := int(position)
		if segment >= segments {
			segment = segments - 1
		}

		blended := colors[segment].BlendHcl(colors[segment+1], position-float64(segment)).Clamped()
		result[i] = ansiFromColorful(blended, isBackground)
	}

	return cacheGradientCells(colors, cells, isBackground, result)
}

// autoShadeDeltaSlope/Floor/Ceiling shape the lightness drop autoShade applies, as a
// fraction of the base color's own HCL lightness: proportional (so a near-black base
// still shifts visibly and a near-white one doesn't overshoot), clamped to a floor (a
// visible ramp even on already-dark colors) and a ceiling (no harsh drop on light ones).
// GradientLast has no cell count to work with (see its doc comment), so the total
// base-to-shade delta is fixed regardless of segment width; these values are tuned so a
// 2-3 cell segment - the common case a single-stop gradient exists for - lands its
// per-step jump close to a JND (~2.3 CIE76 ΔE) rather than reading as a hard color swap.
const (
	autoShadeDeltaSlope   = 0.08
	autoShadeDeltaFloor   = 0.025
	autoShadeDeltaCeiling = 0.05
	autoShadeMinLightness = 0.02
	autoShadeChromaStep   = 0.005
)

// autoShade derives a single-stop (auto-shade) gradient's second stop: same hue, same
// chroma other than what the sRGB gamut forces away, lightness dropped by a clamped
// fraction of the base's own lightness. Blending toward black (the previous approach)
// pulls chroma down linearly alongside lightness, which reads as the color going muddy
// rather than deepening; walking chroma down only as far as IsValid demands keeps the
// hue exact and preserves as much saturation as the gamut allows at the new lightness.
// GradientLast mirrors this on the raw (unresolved) stop text so a segment's trailing
// separator/cap matches the color GradientCells renders the last cell as.
func autoShade(base colorful.Color) colorful.Color {
	h, c, l := base.Hcl()

	delta := math.Max(autoShadeDeltaFloor, math.Min(autoShadeDeltaCeiling, autoShadeDeltaSlope*l))
	l = math.Max(autoShadeMinLightness, l-delta)

	shade := colorful.Hcl(h, c, l)
	for !shade.IsValid() && c > 0 {
		c -= autoShadeChromaStep
		shade = colorful.Hcl(h, c, l)
	}

	return shade.Clamped()
