package terminal

import (
	"testing"

	"github.com/jandedobbeleer/oh-my-posh/src/color"
	"github.com/jandedobbeleer/oh-my-posh/src/shell"

	"github.com/stretchr/testify/assert"
)

const gradientReset = "\x1b[0m"

// colorise mirrors writer.go's colorisePrefix/coloriseSuffix wrapping, so tests can
// build expected output from color.GradientCells results instead of hard-coding codes.
func colorise(c color.Ansi) string {
	return "\x1b[" + c.String() + "m"
}

// saveGradientTestGlobals snapshots the package-level writer state this file's tests
// mutate and restores it via t.Cleanup, so a gradient CurrentColors/BackgroundColor
// value never leaks into a test in another file that runs afterward (see the golang
// skill's "save the original value and restore it" rule for global test state).
func saveGradientTestGlobals(t *testing.T) {
	t.Helper()

	origCurrentColors := CurrentColors
	origParentColors := ParentColors
	origColors := Colors
	origBackgroundColor := BackgroundColor
	origPlain := Plain

	t.Cleanup(func() {
		CurrentColors = origCurrentColors
		ParentColors = origParentColors
		Colors = origColors
		BackgroundColor = origBackgroundColor
		Plain = origPlain
	})
}

func TestWriteGradientRendering(t *testing.T) {
	saveGradientTestGlobals(t)

	bgGradient := color.Ansi("linear-gradient(#FF0000, #0000FF)")
	fgGradient := color.Ansi("linear-gradient(#00FF00, #FF00FF)")
	singleStopGradient := color.Ansi("linear-gradient(#FF0000)")

	resolver := &color.Defaults{}

	bgCells3 := color.GradientCells(bgGradient, 3, resolver, true, nil, nil)
	fgCells3 := color.GradientCells(fgGradient, 3, resolver, false, nil, nil)
	bgCells2 := color.GradientCells(bgGradient, 2, resolver, true, nil, nil)
	fgCells2 := color.GradientCells(fgGradient, 2, resolver, false, nil, nil)
	bgCells4 := color.GradientCells(bgGradient, 4, resolver, true, nil, nil)

	cases := []struct {
		Colors   *color.Set
		Case     string
		Input    string
		Expected string
	}{
		{
			Case:     "background gradient, plain ASCII",
			Input:    "abc",
			Colors:   &color.Set{Foreground: "white", Background: bgGradient},
			Expected: colorise("37") + colorise(bgCells3[0]) + "a" + colorise(bgCells3[1]) + "b" + colorise(bgCells3[2]) + "c" + gradientReset,
		},
		{
			Case:     "foreground gradient, plain ASCII",
			Input:    "abc",
			Colors:   &color.Set{Foreground: fgGradient, Background: "black"},
			Expected: colorise("40") + colorise(fgCells3[0]) + "a" + colorise(fgCells3[1]) + "b" + colorise(fgCells3[2]) + "c" + gradientReset,
		},
		{
			Case:  "both channels gradient",
			Input: "ab",
			Colors: &color.Set{
				Foreground: fgGradient,
				Background: bgGradient,
			},
			Expected: colorise(bgCells2[0]) + colorise(fgCells2[0]) + "a" + colorise(bgCells2[1]) + colorise(fgCells2[1]) + "b" + gradientReset,
		},
		{
			Case:     "wide rune advances index by its width",
			Input:    "a漢b",
			Colors:   &color.Set{Foreground: "white", Background: bgGradient},
			Expected: colorise("37") + colorise(bgCells4[0]) + "a" + colorise(bgCells4[1]) + "漢" + colorise(bgCells4[3]) + "b" + gradientReset,
		},
		{
			Case:     "single-stop gradient auto-shades across cells",
			Input:    "ab",
			Colors:   &color.Set{Foreground: "white", Background: singleStopGradient},
			Expected: colorise("37") + colorise("48;2;255;0;0") + "a" + colorise("48;2;234;0;0") + "b" + gradientReset,
		},
		{
			Case:     "syntactically invalid gradient renders no background escape",
			Input:    "ab",
			Colors:   &color.Set{Foreground: "white", Background: "linear-gradient(#FF0000"},
			Expected: colorise("37") + "ab" + gradientReset,
		},
	}

package prompt

import (
	"strings"
	"testing"

	"github.com/jandedobbeleer/oh-my-posh/src/color"
	"github.com/jandedobbeleer/oh-my-posh/src/config"
	"github.com/jandedobbeleer/oh-my-posh/src/runtime"
	"github.com/jandedobbeleer/oh-my-posh/src/terminal"

	"github.com/stretchr/testify/assert"
)

// gradientStops is the two-stop gradient used across these tests; red -> blue
// keeps the first/last stops trivially distinguishable in assertions.
const gradientStops = color.Ansi("linear-gradient(#FF0000, #0000FF)")

// TestGetPowerlineColorGradient covers engine.go's getPowerlineColor: the
// powerline separator symbol sits at the previous segment's right edge, so a
// gradient background must collapse to its last stop, never the first.
func TestGetPowerlineColorGradient(t *testing.T) {
	previous := &config.Segment{Type: "text", Style: config.Powerline, Background: gradientStops}
	active := &config.Segment{Type: "text", Style: config.Powerline, Background: "green"}

	engine := &Engine{previousActiveSegment: previous, activeSegment: active}

	got := engine.getPowerlineColor()

	assert.Equal(t, gradientStops.GradientLast(), got, "powerline separator color must be the gradient's last stop")
	assert.NotEqual(t, gradientStops.GradientFirst(), got, "powerline separator color must not be the gradient's first stop")
}

// TestGetPowerlineColorSingleStopAutoShade covers the bug report behind the auto-shade
// fix: a single-stop gradient's powerline separator must render the same shaded color
// GradientCells renders the segment's last cell as, not the unshaded configured color -
// otherwise the separator visibly jumps back to a different shade right after the body.
func TestGetPowerlineColorSingleStopAutoShade(t *testing.T) {
	singleStop := color.Ansi("linear-gradient(#3465A4)")
	previous := &config.Segment{Type: "text", Style: config.Powerline, Background: singleStop}
	active := &config.Segment{Type: "text", Style: config.Powerline, Background: "green"}

	engine := &Engine{previousActiveSegment: previous, activeSegment: active}

	got := engine.getPowerlineColor()

	assert.Equal(t, singleStop.GradientLast(), got, "powerline separator must be the auto-shaded last stop")
	assert.NotEqual(t, singleStop.GradientFirst(), got, "powerline separator must not be the unshaded configured color")
}

// TestGetPowerlineColorPaletteReferencedStop pins the fix for a palette reference used
// as an individual gradient STOP rather than the whole gradient value:
// linear-gradient(p:teal) must resolve p:teal before GradientLast shades it, so the
// powerline separator matches the auto-shaded color GradientCells renders the segment's
// last cell as, instead of the raw "p:teal" text GradientLast previously couldn't shade
// without a resolver (it fell through unshaded to the bright, unmodified base color).
func TestGetPowerlineColorPaletteReferencedStop(t *testing.T) {
	engine := New(&runtime.Flags{IsPrimary: true})
	terminal.String()

	palette := color.Palette{"teal": "#179299"}
	origColors := terminal.Colors
	terminal.Colors = color.MakeColors(palette, false, "", engine.Env)
	t.Cleanup(func() { terminal.Colors = origColors })

	previous := &config.Segment{Type: "text", Style: config.Powerline, Background: "linear-gradient(p:teal)"}
	active := &config.Segment{Type: "text", Style: config.Powerline, Background: "green"}

	engine.previousActiveSegment = previous
