// GradientFirst returns the first stop of the gradient. It returns c unchanged when c is not
// a gradient, or when the gradient syntax is invalid.
func (c Ansi) GradientFirst() Ansi {
	stops := c.GradientStops()
	if len(stops) == 0 {
