// GradientLast returns the last stop of the gradient. It returns c unchanged when c is not
// a gradient, or when the gradient syntax is invalid. A dark-gradient/light-gradient's last
// stop is the same auto-shaded color GradientCells renders the segment's last cell as, so
// separators, diamond caps, and parentBackground/parentForeground line up with the body
// instead of jumping back to the unshaded configured color.
func (c Ansi) GradientLast() Ansi {
	stops := c.GradientStops()
	if len(stops) == 0 {
		return c
	}

	last := stops[len(stops)-1]

	if dir := c.shadeDirection(); dir != shadeNone && len(stops) == 1 {
		if clr, err := colorful.Hex(last.String()); err == nil {
			return Ansi(autoShade(clr, dir).Hex())
		}
	}

	return last
}

