	wide := GradientCells("dark-gradient(#179299)", 15, &Defaults{}, true, nil, nil)

	base, _ := colorful.Hex("#179299")
	narrowLast, _ := colorful.Hex(colorful.MakeColor(mustParseRGB(t, narrow[len(narrow)-1])).Hex())
	wideLast, _ := colorful.Hex(colorful.MakeColor(mustParseRGB(t, wide[len(wide)-1])).Hex())

	assert.Greater(t, base.DistanceLab(wideLast), base.DistanceLab(narrowLast), "a 15-cell segment must end further from the base color than a 3-cell one")
}

